import { MemoryStorage } from 'synapse-storage/core'
import { toObservable } from 'synapse-storage/reactive'
import { createSynapse } from 'synapse-storage/utils'

export const pokemonSynapse = createSynapse(async () => {
  await initPokemonApi()                       // the factory's async prologue
  const storage = new MemoryStorage<PokemonState>({ name: 'pokemon-advanced', initialState })

  return {
    storage,
    dependencies: [settingsStorage],           // wait for readiness before assembly
    dependencyTimeout: 10000,                   // ms, default 30000
    dispatcher: new PokemonDispatcher(storage),
    selectors: new PokemonSelectors(storage),
    // settings$ — the external store's state as an Observable (pattern 1, see below)
    effects: new PokemonEffects(pokemonApiClient.getEndpoints(), toObservable(settingsStorage)),
  }
})

import { toObservable } from 'synapse-storage/reactive'

class PokemonEffects extends Effects<PokemonState, PokemonDispatcher> {
  constructor(private readonly api: PokemonApiEndpoints, private readonly settings$: Observable<PokemonSettings>) {
    super()
  }
  // this.settings$ is folded into the pipe via withLatestFrom → the apiCall takes pageSize
}

// assembly:
effects: new PokemonEffects(pokemonApiClient.getEndpoints(), toObservable(settingsStorage))

import type { IStorage, SelectorAPI } from 'synapse-storage/core'

class SettingsSelectors extends Selectors<SettingsState> {
  theme = this.select((s) => s.theme)
  currentUserId: SelectorAPI<string | null>

  constructor(storage: IStorage<SettingsState>, private auth: AuthSynapse['selectors']) {
    super(storage)
    // depends on ANOTHER store's selector → recomputes reactively
    this.currentUserId = this.combine([this.auth.userId], (userId) => userId)
  }
}

// assembly (the factory awaited auth and passed in its selectors):
const auth = await authSynapse
return {
  storage,
  dependencies: [auth],
  selectors: new SettingsSelectors(storage, auth.selectors),
}

class SettingsEffects extends Effects<SettingsState, SettingsDispatcher, { auth: AuthDispatcher }> {
  readonly onLogout = this.effect((action$, _state$, { dispatcher: d, external }) =>
    action$.pipe(
      ofType(external.auth.logout),   // an action from ANOTHER module
      tap(() => d.resetSettings()),
    ),
  )
}

// in assembly the external dispatchers are wired in as externalDispatchers
return {
  storage,
  dependencies: [auth],
  dispatcher: new SettingsDispatcher(storage),
  effects: new SettingsEffects(),
  externalDispatchers: { auth: auth.dispatcher },
}

// The order inside a createSynapse factory:
// 1. Dependencies are ready (Promise.all + timeout); their storage.initialize() is idempotent
// 2. The factory runs → creates storage, dispatcher, selectors, effects
// 3. storage.initialize() + starting the effects

// On timeout — an error is thrown (default 30000ms, pokemon uses 10000):
// 'Dependency 0 ("pokemon-settings") timed out after 10000ms. Check that it initializes correctly.'

class PokemonDispatcher extends Dispatcher<PokemonState> {
  // With a parameter: return = payload (effects catch it — e.g. loadDetails on selectPokemon)
  readonly selectPokemon = this.action((store, id: number | null) => {
    store.update((s) => {
      s.selectedPokemonId = id
      if (id === null) s.selectedPokemon = null
    })
    return id
  })

  // A write with no returned payload (applying a request result) — payload = void
  readonly applyPokemonDetails = this.action((store, details: PokemonDetails) =>
    store.update((s) => { s.selectedPokemon = details }),
  )

  // With meta — arbitrary metadata (2nd argument of this.action)
  readonly toggleFavorite = this.action(
    (store, id: number) => {
      store.update((s) => {
        const idx = s.favorites.indexOf(id)
        if (idx >= 0) s.favorites.splice(idx, 1)
        else s.favorites.push(id)
      })
      return id
    },
    { meta: { description: 'Add/remove from favorites' } },
  )

  // With memoize — a repeated call with the same argument is skipped (doesn't trigger search needlessly)
  readonly setSearchQuery = this.action(
    (store, query: string) => { store.set('searchQuery', query); return query },
    { memoize: (current, previous) => current === previous },
  )
}

class PokemonDispatcher extends Dispatcher<PokemonState> {
  readonly loadMore = this.signal<void>('Load the next page')
}

class PokemonDispatcher extends Dispatcher<PokemonState> {
  readonly loadList = this.apiActions<void>((s) => s.api.listRequest)
  readonly loadDetails = this.apiActions<void>((s) => s.api.detailsRequest)
}

// Usage:
d.loadList()             // init: listRequest status → idle, the intent goes to effects
d.loadList.loading()     // status → loading
d.loadList.success()     // status → success
d.loadList.failure('msg')// status → error, error = 'msg'
d.loadList.reset()       // status → reset

// In an effect: we react to the INTENT to load (init), not to statuses
action$.pipe(ofType(d.loadList), /* ... start the request ... */)

// To react to a RESULT — listen for the specific phase explicitly:
action$.pipe(ofType(d.loadList.success), /* ... */)
action$.pipe(ofType(d.loadList.failure), /* ... */)

class PokemonDispatcher extends Dispatcher<PokemonState> {
  // Basic + notifyAfterSubscribe (fire immediately on subscribe) + meta
  readonly watchFavoriteCount = this.watcher({
    selector: (state) => state.favorites.length,
    notifyAfterSubscribe: true,
    meta: { description: 'tracking the number of favorites' },
  })

  // With shouldTrigger — filtering out false triggers
  readonly watchSelected = this.watcher({
    selector: (state) => state.selectedPokemonId,
    shouldTrigger: (prev, current) => prev !== current,
  })
}

// Subscribe — through the watchers registry (calling the factory → Observable)
const sub = dispatcher.watchers.watchFavoriteCount().subscribe((action) => {
  console.log('favorites:', action.payload)
})
sub.unsubscribe()

// Calling actions — through the instance's typed fields
dispatcher.selectPokemon(25)
dispatcher.setSearchQuery('pika')
dispatcher.loadMore()

// Or through the dispatch registry
dispatcher.dispatch.selectPokemon.actionType  // '[pokemon-advanced]selectPokemon'
dispatcher.dispatch.toggleFavorite.meta       // { description: 'Add/remove from favorites' }

// Subscribing to watchers (RxJS Observable)
const sub = dispatcher.watchers.watchFavoriteCount().subscribe((action) => {
  console.log('favorites:', action.payload)
})
sub.unsubscribe()

// Subscribing to ALL actions (effects are built on this stream)
dispatcher.actions.subscribe((action) => {
  console.log(action.type, action.payload)
})

// Cleanup
dispatcher.destroy()

const eventBusHandle = createEventBus({
  name: 'pokemon-events',     // name (for singleton/debugging)
  autoCleanup: true,          // auto-cleanup of old events
  maxEvents: 1000,            // max stored events (default 1000)
})

// createEventBus returns a SynapseModule handle (lazy, PromiseLike) —
// the factory runs on the first await/ready()
const eventBus = await eventBusHandle

// The result (Synapse<EventBusState, EventBusDispatcher, undefined>):
// {
//   storage: IStorage<EventBusState>       — the state storage
//   actions: EventBusDispatcher            — typed actions (alias of dispatcher)
//   dispatcher: EventBusDispatcher         — the same dispatcher instance
//   selectors: undefined                   — the bus has no selectors
//   state$: Observable<EventBusState>      — the state stream (always present)
//   destroy: () => Promise<void>           — cleanup
// }

// EventBusState:
// {
//   events: Record<string, EventBusEvent>
//   subscriptions: Record<string, SubscriptionInfo>
// }

const eventBus = await createEventBus({ name: 'pokemon-events' })

// Publishing an event
const result = await eventBus.actions.publish({
  event: 'POKEMON_SELECTED',            // event type (string)
  data: { id: 25, name: 'pikachu' },    // arbitrary data
  metadata: {                           // optional metadata
    priority: 'high',                   // 'low' | 'normal' | 'high'
    ttl: 60000,                         // event time-to-live (ms)
  },
})

// The result:
// {
//   eventId: string    — the unique event ID
//   event: string      — the event type
//   data: any          — the data
// }

// EventBusEvent (stored in storage):
// {
//   id: string
//   event: string
//   data: any
//   metadata: { ttl?: number | null, priority?: 'low' | 'normal' | 'high' }
//   timestamp: number
// }

// Subscribing to a specific event
const { subscriptionId, unsubscribe } = await eventBus.actions.subscribe({
  eventPattern: 'POKEMON_SELECTED',  // exact match
  handler: (data, event) => {
    // data — event.data (the payload)
    // event — the full EventBusEvent object
    console.log(data)               // { id: 25, name: 'pikachu' }
    console.log(event.event)        // 'POKEMON_SELECTED'
    console.log(event.timestamp)    // 1716633600000
  },
})

// Wildcard patterns
await eventBus.actions.subscribe({
  eventPattern: 'POKEMON_*',       // all events starting with POKEMON_
  handler: (data, event) => {      // POKEMON_SELECTED, POKEMON_LOADED, ...
    console.log(event.event, data)
  },
})

await eventBus.actions.subscribe({
  eventPattern: '*',               // ALL events
  handler: (data, event) => {
    console.log('Any event:', event.event)
  },
})

// Filter by priority
await eventBus.actions.subscribe({
  eventPattern: 'FAVORITE_*',
  handler: (data, event) => { ... },
  options: { priority: 'high' },   // only high-priority events
})

// Unsubscribe
unsubscribe()

// Get the history for an event type
const history = await eventBus.actions.getEventHistory({
  eventType: 'POKEMON_SELECTED',  // the event type
  limit: 10,                       // max records (default 100)
})

// Returns EventBusEvent[] — sorted by timestamp (newest first)
// [
//   { id: '...', event: 'POKEMON_SELECTED', data: {...}, timestamp: 1716633600000 },
//   { id: '...', event: 'POKEMON_SELECTED', data: {...}, timestamp: 1716633500000 },
// ]

const subscriptions = await eventBus.actions.getActiveSubscriptions()

// Returns an array:
// [
//   {
//     id: string,          — the subscription ID
//     pattern: string,     — the pattern ('POKEMON_*', '*', etc.)
//     options: {...},       — options (priority etc.)
//     createdAt: number,   — creation time
//   }
// ]

// Clear old events
await eventBus.actions.clearEvents({
  olderThan: 60000,                // remove events older than 60 seconds
})

// Clear all events
await eventBus.actions.clearEvents({})

